class InventoryService:
    def validate_items(self, items: List[CartItem]) -> Dict[str, Any]:
        if not items:
            raise ValidationError("Cart is empty")

        validated_items = []
        subtotal = Decimal("0.00")

        for item in items:
            if item.quantity <= 0:
                raise ValidationError(f"Invalid quantity for SKU {item.sku}")
            if not item.active:
                raise ValidationError(f"Item {item.sku} is inactive")
            if item.stock < item.quantity:
                raise ValidationError(f"Insufficient stock for SKU {item.sku}")
            if item.unit_price < 0:
                raise ValidationError(f"Invalid price for SKU {item.sku}")

            line_subtotal = item.subtotal()
            subtotal += line_subtotal
            validated_items.append(
                {
                    "sku": item.sku,
                    "name": item.name,
                    "unit_price": money(item.unit_price),
                    "quantity": item.quantity,
                    "taxable": item.taxable,
                    "line_subtotal": money(line_subtotal),
                }
            )

        return {
            "items": validated_items,
            "subtotal": money(subtotal),
        }


class DiscountService:
    def __init__(self, available_codes: Dict[str, DiscountCode]):
        self.available_codes = available_codes

    def apply_discounts(
        self,
        user: User,
        validated_cart: Dict[str, Any],
        discount_codes: Optional[List[str]],
    ) -> Dict[str, Any]:
        items = validated_cart["items"]
        subtotal = money(validated_cart["subtotal"])
        discount_codes = discount_codes or []

        applied_discounts = []
        total_discount = Decimal("0.00")

        for raw_code in discount_codes:
            code_key = raw_code.strip().upper()
            if not code_key:
                continue

            discount = self.available_codes.get(code_key)
            if not discount:
                raise ValidationError(f"Unknown discount code: {code_key}")
            if not discount.applies_to_user(user):
                raise PermissionError(f"User not permitted to use discount code: {code_key}")
            if subtotal < money(discount.min_subtotal):
                raise ValidationError(f"Discount code {code_key} requires minimum subtotal {money(discount.min_subtotal)}")

            eligible_subtotal = subtotal
            if discount.applicable_skus is not None:
                eligible_subtotal = sum(
                    (item["line_subtotal"] for item in items if item["sku"] in discount.applicable_skus),
                    Decimal("0.00"),
                )
                eligible_subtotal = money(eligible_subtotal)

            if eligible_subtotal <= 0:
                continue

            if discount.kind == "percent":
                discount_amount = money(eligible_subtotal * (discount.value / Decimal("100")))
            elif discount.kind == "fixed":
                discount_amount = money(discount.value)
            else:
                raise ValidationError(f"Unsupported discount type for code: {code_key}")

            remaining = money(subtotal - total_discount)
            discount_amount = min(discount_amount, remaining)
            if discount_amount <= 0:
                continue

            total_discount += discount_amount
            total_discount = money(total_discount)
            applied_discounts.append(
                {
                    "code": code_key,
                    "kind": discount.kind,
                    "value": money(discount.value),
                    "amount": money(discount_amount),
                }
            )

        discounted_subtotal = money(subtotal - total_discount)

        return {
            **validated_cart,
            "applied_discounts": applied_discounts,
            "discount_total": money(total_discount),
            "discounted_subtotal": discounted_subtotal,
        }


class TaxService:
    def calculate_tax(self, discounted_cart: Dict[str, Any], tax_rate: Decimal) -> Dict[str, Any]:
        tax_rate = Decimal(str(tax_rate))
        if tax_rate < 0:
            raise ValidationError("Tax rate cannot be negative")

        taxable_subtotal = sum(
            (item["line_subtotal"] for item in discounted_cart["items"] if item["taxable"]),
            Decimal("0.00"),
        )
        taxable_subtotal = money(taxable_subtotal)

        subtotal = money(discounted_cart["subtotal"])
        discount_total = money(discounted_cart["discount_total"])

        if subtotal > 0 and discount_total > 0:
            taxable_discount_share = money(discount_total * (taxable_subtotal / subtotal))
        else:
            taxable_discount_share = Decimal("0.00")

        taxable_after_discount = money(max(Decimal("0.00"), taxable_subtotal - taxable_discount_share))
        tax_total = money(taxable_after_discount * tax_rate)
        total = money(discounted_cart["discounted_subtotal"] + tax_total)

        return {
            **discounted_cart,
            "taxable_subtotal": taxable_subtotal,
            "tax_total": tax_total,
            "total": total,
            "tax_rate": tax_rate,
        }


class PaymentGateway:
    def charge(self, amount: Decimal, payment_method: PaymentMethod) -> PaymentResult:
        amount = money(amount)
        if amount <= 0:
            return PaymentResult(
                success=False,
                status="failed",
                amount_charged=Decimal("0.00"),
                error="Charge amount must be greater than zero",
            )
        if not payment_method.token:
            return PaymentResult(
                success=False,
                status="failed",
                amount_charged=Decimal("0.00"),
                error="Missing payment token",
            )

        return PaymentResult(
            success=True,
            transaction_id=f"txn_{uuid.uuid4().hex[:16]}",
            status="succeeded",
            amount_charged=amount,
            error=None,
        )


class OrderRepository:
    def __init__(self):
        self._orders: Dict[str, OrderRecord] = {}

    def create(self, order: OrderRecord) -> OrderRecord:
        self._orders[order.order_id] = order
        return order

    def get(self, order_id: str) -> Optional[OrderRecord]:
        return self._orders.get(order_id)


class CheckoutService:
    def __init__(
        self,
        inventory_service: InventoryService,
        discount_service: DiscountService,
        tax_service: TaxService,
        payment_gateway: PaymentGateway,
        order_repository: OrderRepository,
    ):
        self.inventory_service = inventory_service
        self.discount_service = discount_service
        self.tax_service = tax_service
        self.payment_gateway = payment_gateway
        self.order_repository = order_repository

    def checkout(
        self,
        user: User,
        cart_items: List[CartItem],
        payment_method: PaymentMethod,
        tax_rate: Decimal,
        discount_codes: Optional[List[str]] = None,
        currency: str = "USD",
        metadata: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        step1 = self.inventory_service.validate_items(cart_items)
        step2 = self.discount_service.apply_discounts(user, step1, discount_codes)
        step3 = self.tax_service.calculate_tax(step2, tax_rate)
        step4 = self.payment_gateway.charge(step3["total"], payment_method)

        if not step4.success or not step4.transaction_id:
            raise PaymentError(step4.error or "Payment processing failed")

        order = OrderRecord(
            order_id=f"ord_{uuid.uuid4().hex[:16]}",
            user_id=user.id,
            items=step3["items"],
            subtotal=money(step3["subtotal"]),
            discount_total=money(step3["discount_total"]),
            tax_total=money(step3["tax_total"]),
            total=money(step3["total"]),
            currency=currency,
            payment_transaction_id=step4.transaction_id,
            applied_discounts=[d["code"] for d in step3["applied_discounts"]],
            metadata=metadata or {},
        )
        step5 = self.order_repository.create(order)

        return {
            "order_id": step5.order_id,
            "user_id": step5.user_id,
            "items": step5.items,
            "subtotal": str(step5.subtotal),
            "discount_total": str(step5.discount_total),
            "tax_total": str(step5.tax_total),
            "total": str(step5.total),
            "currency": step5.currency,
            "payment": {
                "transaction_id": step4.transaction_id,
                "status": step4.status,
                "amount_charged": str(step4.amount_charged),
            },
            "applied_discounts": step5.applied_discounts,
            "metadata": step5.metadata,
        }


